import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

describe("mergeIntervals", () => {
  describe("empty input", () => {
    it("returns [] for an empty array", () => {
      expect(mergeIntervals([])).toEqual([]);
    });
  });

  describe("overlapping intervals are merged", () => {
    it("merges the documented example [1,4],[3,6] -> [1,6]", () => {
      expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
    });

    it("merges an interval fully contained in another", () => {
      expect(mergeIntervals([[1, 10], [3, 5]])).toEqual([[1, 10]]);
    });

    it("keeps the larger end when the second interval ends earlier", () => {
      expect(mergeIntervals([[1, 8], [2, 4]])).toEqual([[1, 8]]);
    });

    it("merges a chain of successively overlapping intervals", () => {
      expect(mergeIntervals([[1, 3], [2, 5], [4, 8]])).toEqual([[1, 8]]);
    });

    it("merges duplicate intervals into one", () => {
      expect(mergeIntervals([[2, 5], [2, 5]])).toEqual([[2, 5]]);
    });
  });

  describe("touching intervals are merged", () => {
    it("merges the documented example [1,2],[2,3] -> [1,3]", () => {
      expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
    });

    it("merges intervals that touch at a boundary out of order", () => {
      expect(mergeIntervals([[5, 7], [3, 5]])).toEqual([[3, 7]]);
    });
  });

  describe("disjoint intervals stay separate", () => {
    it("keeps two non-overlapping intervals separate", () => {
      expect(mergeIntervals([[1, 2], [4, 5]])).toEqual([[1, 2], [4, 5]]);
    });

    it("does not merge intervals separated by a gap of one", () => {
      expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
    });

    it("returns a single interval unchanged", () => {
      expect(mergeIntervals([[3, 9]])).toEqual([[3, 9]]);
    });
  });

  describe("output is sorted by start ascending", () => {
    it("sorts disjoint intervals given out of order", () => {
      expect(mergeIntervals([[5, 6], [1, 2], [3, 4]])).toEqual([
        [1, 2],
        [3, 4],
        [5, 6],
      ]);
    });

    it("sorts and merges a mixed unsorted input", () => {
      expect(mergeIntervals([[8, 10], [1, 3], [2, 6], [15, 18]])).toEqual([
        [1, 6],
        [8, 10],
        [15, 18],
      ]);
    });

    it("handles intervals sharing the same start", () => {
      expect(mergeIntervals([[1, 3], [1, 5]])).toEqual([[1, 5]]);
    });
  });

  describe("supports zero-width, negative, and non-integer bounds", () => {
    it("merges a zero-width interval touching another", () => {
      expect(mergeIntervals([[1, 3], [3, 3]])).toEqual([[1, 3]]);
    });

    it("keeps a disjoint zero-width interval separate", () => {
      expect(mergeIntervals([[5, 5], [1, 2]])).toEqual([[1, 2], [5, 5]]);
    });

    it("handles negative coordinates", () => {
      expect(mergeIntervals([[-5, -2], [-3, 0]])).toEqual([[-5, 0]]);
    });

    it("handles fractional bounds", () => {
      expect(mergeIntervals([[1.5, 2.5], [2.5, 3.0]])).toEqual([[1.5, 3.0]]);
    });
  });

  describe("throws RangeError for invalid pairs", () => {
    it("throws when a pair has start > end", () => {
      expect(() => mergeIntervals([[5, 1]])).toThrow(RangeError);
    });

    it("throws when an invalid pair appears among valid ones", () => {
      expect(() => mergeIntervals([[1, 2], [9, 4], [5, 6]])).toThrow(RangeError);
    });

    it("includes the offending interval in the message", () => {
      expect(() => mergeIntervals([[7, 3]])).toThrow("[7, 3]");
    });

    it("does not throw for a valid zero-width pair (start === end)", () => {
      expect(() => mergeIntervals([[4, 4]])).not.toThrow();
    });
  });

  describe("does not mutate input", () => {
    it("leaves the input array and its pairs unchanged", () => {
      const input = [[3, 6], [1, 4]];
      const snapshot = [[3, 6], [1, 4]];
      mergeIntervals(input);
      expect(input).toEqual(snapshot);
      expect(input[0]).toEqual([3, 6]);
      expect(input[1]).toEqual([1, 4]);
    });

    it("returns a new array, not a reference into the input", () => {
      const input = [[1, 2]];
      const result = mergeIntervals(input);
      expect(result).not.toBe(input);
      expect(result[0]).not.toBe(input[0]);
    });

    it("does not mutate pairs when merging occurs", () => {
      const a = [1, 4];
      const b = [3, 6];
      mergeIntervals([a, b]);
      expect(a).toEqual([1, 4]);
      expect(b).toEqual([3, 6]);
    });
  });
});

